<body>
<div class="container">
  <!-- Header -->
  <div class="header">
    <div class="logo-area">
      <div class="logo-badge">CSP · Daily Radar</div>
      <div class="logo-title">Morning Signal</div>
    </div>
    <div class="date-area">
      <div class="date-big" id="date-display">Loading...</div>
      <div class="time-display" id="time-display">--:--</div>
    </div>
  </div>

  <!-- Priority Bar -->
  <div class="priority-bar">
    <span class="priority-tag tag-1">① Vibe Coding</span>
    <span class="priority-tag tag-2">② 투자·경제</span>
    <span class="priority-tag tag-3">③ AX·AI 트렌드</span>
    <span class="priority-tag tag-4">④ HR SaaS</span>
  </div>

  <!-- Generate Section -->
  <div class="generate-section">
    <button class="generate-btn" id="generate-btn" onclick="generateBriefing()">
      <span class="btn-icon">◎</span>
      오늘의 레이더 스캔 시작
    </button>
  </div>

  <!-- Loading -->
  <div class="loading-area" id="loading-area">
    <div class="loading-spinner"></div>
    <div class="loading-text" id="loading-text">Scanning signals...</div>
  </div>

  <!-- Output -->
  <div id="briefing-output">
    <!-- Mission Box -->
    <div class="mission-box" id="mission-box"></div>

    <!-- Section Blocks -->
    <div id="sections-container"></div>
  </div>

  <!-- Footer -->
  <div class="footer">
    <div class="footer-left">CSP-OS · GROWTH RADAR v1.0</div>
    <div class="footer-right">북마크 후 매일 10:00 열기 🔖</div>
  </div>
</div>

<script>
// Clock
function updateClock() {
  const now = new Date();
  const days = ['일','월','화','수','목','금','토'];
  document.getElementById('date-display').textContent =
    `${now.getFullYear()}.${String(now.getMonth()+1).padStart(2,'0')}.${String(now.getDate()).padStart(2,'0')} ${days[now.getDay()]}`;
  document.getElementById('time-display').textContent =
    `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;
}
updateClock();
setInterval(updateClock, 1000);

const LOADING_MESSAGES = [
  'Vibe Coding 생태계 스캔 중...',
  '투자 시그널 포착 중...',
  'AI/AX 트렌드 분석 중...',
  'HR SaaS 벤치마크 수집 중...',
  'CSP 성장 레이더 조준 중...',
];

async function generateBriefing() {
  const btn = document.getElementById('generate-btn');
  const loading = document.getElementById('loading-area');
  const output = document.getElementById('briefing-output');
  const loadingText = document.getElementById('loading-text');

  btn.disabled = true;
  loading.style.display = 'flex';
  output.style.display = 'none';

  // Rotate loading messages
  let msgIdx = 0;
  const msgInterval = setInterval(() => {
    loadingText.textContent = LOADING_MESSAGES[msgIdx % LOADING_MESSAGES.length];
    msgIdx++;
  }, 1200);

  const today = new Date().toLocaleDateString('ko-KR', {
    year: 'numeric', month: 'long', day: 'numeric', weekday: 'long'
  });

  const systemPrompt = `당신은 CSP(Creative Solution Provider)의 전용 성장 레이더 AI입니다.
CSP 프로필:
- HR 전문가 17년 경력 + Vibe Coder (SW 비전공)
- 현재: 대형 제조업 AX 내재화 전략 담당 (AI 교육, 조직건강도 시스템, Skill Ontology)
- 목표: HR 자동화 SaaS 창업 (5~6년 내), 경제적 자유
- 철학: "심리학이 코드가 되고, 철학이 알고리즘이 되고, HR 경험이 SaaS 제품이 된다"
- 투자: 한국 부동산, 채권/ETF, 국내외 주식

콘텐츠 우선순위:
1. Vibe Coding & 개발 생태계 (Claude Code, Cursor, LLM coding trends)
2. 투자 & 경제 시그널 (한국 증시, 미국 시장, 매크로)
3. AX/AI 트렌드 & 글로벌 사례
4. HR SaaS & HRTech 벤치마크

오늘 날짜: ${today}

JSON 형식으로만 응답하세요 (마크다운 코드블록 없이 순수 JSON):
{
  "todayMission": "오늘 CSP가 집중해야 할 한 줄 미션 (DM Serif 폰트로 보여질 인상적인 문장, 한국어, 20자 이내)",
  "sections": [
    {
      "id": "vibe",
      "icon": "⌨",
      "title": "Vibe Coding & 개발 생태계",
      "colorClass": "tag-1",
      "dotClass": "dot-green",
      "signals": [
        {
          "label": "시그널 제목 (도구명/트렌드명)",
          "desc": "CSP 관점에서 실용적으로 해석한 2~3문장 설명. HR SaaS 빌딩이나 현업 적용 관점 포함.",
          "highlight": "핵심 키워드",
          "highlightClass": "highlight-green"
        }
      ],
      "reflection": "이 영역에서 CSP가 오늘 1가지 실행해볼 수 있는 구체적 액션 또는 질문"
    },
    {
      "id": "invest",
      "icon": "◈",
      "title": "투자 & 경제 시그널",
      "colorClass": "tag-2",
      "dotClass": "dot-orange",
      "signals": [],
      "reflection": ""
    },
    {
      "id": "ax",
      "icon": "◉",
      "title": "AX·AI 트렌드",
      "colorClass": "tag-3",
      "dotClass": "dot-purple",
      "signals": [],
      "reflection": ""
    },
    {
      "id": "hr",
      "icon": "◇",
      "title": "HR SaaS & HRTech",
      "colorClass": "tag-4",
      "dotClass": "dot-red",
      "signals": [],
      "reflection": ""
    }
  ]
}

각 section의 signals는 2~3개. 투자 섹션은 매크로 시그널 + 한국 시장 각도 포함. 
모든 내용은 한국어. CSP의 성장과 직결되는 인사이트 위주. 뉴스 나열이 아닌 CSP 관점 해석.`;

  try {
    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 1000,
        system: systemPrompt,
        messages: [{ role: 'user', content: '오늘의 CSP 성장 레이더 브리핑을 생성해줘.' }]
      })
    });

    const data = await response.json();
    const raw = data.content.map(b => b.text || '').join('');
    const clean = raw.replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(clean);

    clearInterval(msgInterval);
    loading.style.display = 'none';
    renderBriefing(parsed);
    output.style.display = 'block';
  } catch (err) {
    clearInterval(msgInterval);
    loading.style.display = 'none';
    output.style.display = 'block';
    renderError();
  }

  btn.disabled = false;
  btn.innerHTML = '<span class="btn-icon">◎</span> 다시 스캔하기';
}

function renderBriefing(data) {
  // Mission
  document.getElementById('mission-box').innerHTML = `
    <div class="mission-label">── Today's Focus ──</div>
    <div class="mission-text">${data.todayMission}</div>
  `;

  // Sections
  const container = document.getElementById('sections-container');
  container.innerHTML = '';

  const colorMap = {
    'tag-1': 'rgba(106,247,200,0.15)',
    'tag-2': 'rgba(247,162,106,0.15)',
    'tag-3': 'rgba(124,106,247,0.15)',
    'tag-4': 'rgba(247,106,138,0.15)',
  };

  data.sections.forEach((sec, idx) => {
    const signalsHtml = sec.signals.map(sig => `
      <div class="signal-row">
        <div class="signal-dot ${sec.dotClass}"></div>
        <div class="signal-text">
          <div class="signal-label">
