            <div class="reflection-text">${sec.reflection}</div>
          </div>
        ` : ''}
      </div>
    `;
    container.appendChild(block);
  });
}

function renderError() {
  document.getElementById('mission-box').innerHTML = `
    <div class="mission-label">── Notice ──</div>
