<div class="container">
  <div class="header">
    <div class="logo-area">
      <div class="logo-badge">CSP · Daily Radar</div>
      <div class="logo-title">Morning Signal</div>
    </div>
    <div class="date-area">
      <div class="date-big" id="date-display">Loading...</div>
      <div class="time-display" id="time-display">--:--</div>
    </div>
  </div>

  <div class="priority-bar">
    <span class="priority-tag tag-1">① Vibe Coding</span>
    <span class="priority-tag tag-2">② 투자·경제</span>
    <span class="priority-tag tag-3">③ AX·AI 트렌드</span>
    <span class="priority-tag tag-4">④ HR SaaS</span>
  </div>

  <div class="generate-section">
    <button class="generate-btn" id="generate-btn" onclick="generateBriefing()">
      <span class="btn-icon">◎</span>
      오늘의 레이더 스캔 시작
    </button>
  </div>

  <div class="loading-area" id="loading-area">
    <div class="loading-spinner"></div>
    <div class="loading-text" id="loading-text">Scanning signals...</div>
  </div>

