function renderBriefing(data) {
  document.getElementById('mission-box').innerHTML = `
    <div class="mission-label">── Today's Focus ──</div>
    <div class="mission-text">${data.todayMission}</div>
  `;

  const container = document.getElementById('sections-container');
  container.innerHTML = '';

  const colorMap = {
    'tag-1': 'rgba(106,247,200,0.15)',
    'tag-2': 'rgba(247,162,106,0.15)',
    'tag-3': 'rgba(124,106,247,0.15)',
    'tag-4': 'rgba(247,106,138,0.15)',
  };

  data.sections.forEach((sec, idx) => {
    const signalsHtml = sec.signals.map(sig => `
      <div class="signal-row">
        <div class="signal-dot ${sec.dotClass}"></div>
        <div class="signal-text">
          <div class="signal-label">
            ${sig.highlight ? `<span class="highlight ${sig.highlightClass}">${sig.highlight}</span> ` : ''}${sig.label}
          </div>
          <div class="signal-desc">${sig.desc}</div>
        </div>
      </div>
    `).join('');

    const block = document.createElement('div');
    block.className = 'section-block';
    block.innerHTML = `
      <div class="section-header">
        <span class="section-num">0${idx + 1}</span>
        <span class="section-icon">${sec.icon}</span>
        <span class="section-title">${sec.title}</span>
        <span class="section-tag ${sec.colorClass}" style="background:${colorMap[sec.colorClass]}">SIGNAL</span>
      </div>
      <div class="section-body">
        ${signalsHtml}
        ${sec.reflection ? `
          <div class="reflection-box">
            <div class="reflection-label">→ CSP Action</div>
            <div class="reflection-text">${sec.reflection}</div>
          </div>
        ` : ''}
      </div>
    `;
    container.appendChild(block);
  });
}

function renderError(err) {
  document.getElementById('mission-box').innerHTML = `
    <div class="mission-label">── Error ──</div>
    <div class="mission-text" style="font-size:15px; font-family:'Noto Sans KR'; color:#f76a8a;">
      브리핑 생성 중 오류가 발생했습니다. Claude.ai 환경에서 다시 시도해주세요.
    </div>
  `;
  document.getElementById('sections-container').innerHTML = '';
}
